function getLangFromUrl(): Lang {
  if (typeof window === 'undefined') return 'en';
  const first = window.location.pathname.split('/')[1];
  if (first && first in S) return first as Lang;
  return 'en';
}

export function useToolI18n(lang?: string) {
  const resolved = lang && lang in S ? lang as Lang : getLangFromUrl();
  return S[resolved] ?? S.en;
}

function getToolKeyFromUrl(): string | null {
  if (typeof window === 'undefined') return null;
  const parts = window.location.pathname.split('/').filter(Boolean);
  if (parts.length >= 3) return `${parts[1]}/${parts[2]}`;
  return null;
}

export function useToolInfo(): { name: string; description: string } {
  const lang = getLangFromUrl();
  const key = getToolKeyFromUrl();
  const t = translations[lang as keyof typeof translations] ?? translations.en;
  if (key && t.tools[key]) {
    return { name: t.tools[key].name, description: t.tools[key].description };
  }
  return { name: '', description: '' };
}

