export function getUnitLabel(category: UnitCategory, unitKey: string, lang?: string): string {
  const resolved = lang && lang in unitLabelMap ? lang : (typeof window !== 'undefined' ? window.location.pathname.split('/')[1] : 'en');
  const map = unitLabelMap[resolved] ?? unitLabelMap.en;
  const fullKey = category + '/' + unitKey;
  return map[fullKey] ?? unitLabelMap.en[fullKey] ?? unitKey;
}
